import { createAccountControllerBundle } from '../modules/account/controllerBundle.js';
import { createAuthUiRuntime } from '../ui/authRuntime.js';

export function createAccountAuthBundle(deps = {}) {
  const {
    addLocalAccount,
    appState,
    applyCloudSessionConfig,
    applyGoogleAccount,
    applyLanguage,
    applySidebarState,
    buildCloudSessionCommunity,
    buildCloudSessionState,
    buildGoogleAccountFromPayload,
    buildLocalAccount,
    clearProblemLookupCaches,
    cloudApi,
    cloudStatePayload,
    consumeIncomingCapture,
    createBaseState,
    DEFAULT_GRADUATION_TERM,
    documentRef: document,
    elements: els,
    getAuthErrorMessage,
    getAuthReadyMessage,
    getCurrentUser,
    getGoogleClientId,
    getUserCatalogProblems,
    getVerificationErrorMessage,
    GOOGLE_LOGIN_ENABLED,
    hashPassword,
    initDefaultCountry = "china",
    initDefaultRegion = "上海",
    invalidateLeaderboardCloud,
    loadState,
    loadStateForUser,
    localStatePayload,
    makeId,
    mergeCloudCommunity,
    mergeCloudState,
    mergeProblemStates,
    migrateLegacyState,
    normalizeAccount,
    normalizeCountry,
    normalizeEmail,
    normalizeGraduationTerm,
    normalizeLeaderboardSettings,
    normalizeRegionForCountry,
    normalizeCommunityStore,
    normalizeState,
    parseJwt,
    problemSocialState,
    pruneProblemCatalog,
    queueCloudSync,
    refreshProblemCatalog,
    refreshProblemSocial,
    renderAll,
    restoreRouteModule,
    saveAuth,
    saveCloudConfig,
    saveCommunity,
    saveState,
    setCurrentUserId,
    setGoogleClientId,
    showAuthMessage,
    switchModule,
    t,
    upsertLocalAccount,
    userState,
    userStateKey,
    windowRef: window,
    writeUserState
  } = deps;

  let accountAuthController = null;
  const handleGoogleCredential = (response) => accountAuthController?.handleGoogleCredential(response);

  const authUiRuntime = createAuthUiRuntime({
    elements: els,
    documentRef: document,
    windowRef: window,
    googleLoginEnabled: GOOGLE_LOGIN_ENABLED,
    getGoogleClientId: () => getGoogleClientId(appState.auth),
    handleGoogleCredential,
    showAuthMessage,
    t
  });

  const accountControllerBundle = createAccountControllerBundle({
    elements: els,
    documentRef: document,
    windowRef: window,
    getAppState: () => appState,
    getUserStateStore: () => userState,
    getCurrentUser,
    loadState,
    clearProblemLookupCaches,
    problemSocialState,
    pruneProblemCatalog,
    consumeIncomingCapture,
    applySidebarState,
    getAuthReadyMessage,
    renderGoogleClientInput: authUiRuntime.renderGoogleClientInput,
    applyLanguage,
    renderAll,
    restoreRouteModule,
    refreshProblemCatalog,
    refreshProblemSocial,
    cloudApi,
    cloudStatePayload,
    getUserCatalogProblems,
    normalizeAccount,
    upsertLocalAccount,
    applyCloudSessionConfig,
    saveCloudConfig,
    buildCloudSessionState,
    loadStateForUser,
    mergeProblemStates,
    mergeCloudState,
    normalizeState,
    writeUserState,
    localStatePayload,
    userStateKey,
    buildCloudSessionCommunity,
    normalizeCommunityStore,
    mergeCloudCommunity,
    saveCommunity,
    queueCloudSync,
    invalidateLeaderboardCloud,
    defaultCountry: initDefaultCountry,
    defaultRegion: initDefaultRegion,
    defaultGraduationTerm: DEFAULT_GRADUATION_TERM,
    normalizeEmail,
    makeId,
    hashPassword,
    buildLocalAccount,
    addLocalAccount,
    setCurrentUserId,
    setGoogleClientId,
    getGoogleClientId: () => getGoogleClientId(appState.auth),
    buildGoogleAccountFromPayload,
    applyGoogleAccount,
    parseJwt,
    saveAuth,
    createBaseState,
    migrateLegacyState,
    initGoogleLogin: authUiRuntime.initGoogleLogin,
    setRegisterCodeButtonBusy: authUiRuntime.setRegisterCodeButtonBusy,
    startRegisterCodeCooldown: authUiRuntime.startRegisterCodeCooldown,
    showAuthMessage,
    getVerificationErrorMessage,
    getAuthErrorMessage,
    getUserState: () => userState.value,
    normalizeCountry,
    normalizeRegionForCountry,
    normalizeGraduationTerm,
    normalizeLeaderboardSettings,
    saveState,
    switchModule,
    t
  });

  accountAuthController = accountControllerBundle.accountAuthController;

  return {
    accountAuthController,
    initGoogleLogin: authUiRuntime.initGoogleLogin,
    loginLocal: accountControllerBundle.loginLocal,
    logout: accountControllerBundle.logout,
    registerLocal: accountControllerBundle.registerLocal,
    resetEmailAuthFlow: accountControllerBundle.resetEmailAuthFlow,
    renderGoogleClientInput: authUiRuntime.renderGoogleClientInput,
    renderGooglePlaceholder: authUiRuntime.renderGooglePlaceholder,
    renderSession: accountControllerBundle.renderSession,
    renderUserChip: accountControllerBundle.renderUserChip,
    saveAccount: accountControllerBundle.saveAccount,
    saveGoogleClientId: accountControllerBundle.saveGoogleClientId,
    sendRegisterVerificationCode: accountControllerBundle.sendRegisterVerificationCode,
    submitEmailAuth: accountControllerBundle.submitEmailAuth,
    switchAuthTab: accountControllerBundle.switchAuthTab
  };
}
